customCSS:
/* Theme Modal */
.modal { background: rgba(0,0,0,0.42) !important; backdrop-filter: none !important; -webkit-backdrop-filter: none !important; }
.modal-content { background: rgba(0,0,0,0.9) !important; border: 2px solid #fff !important; border-radius: 0 !important; box-shadow: none !important; color: #fff !important; }
.modal-title, .settings-title, .modal-content h4 { color: #fff !important; text-transform: uppercase !important; letter-spacing: 0 !important; }
.app-dialog-message, .trigger-description, .community-template .description { color: #fff !important; }
.import-hint, .settings-help, .hotkey-help, .range-labels, .community-template .task-count { color: #d6d6d6 !important; }
.community-template { background: transparent !important; border: 1px solid #fff !important; }
.modal-btn.primary { background: #fff !important; border: 2px solid #fff !important; color: #000 !important; }
.modal-btn.secondary { background: transparent !important; border: 2px solid #fff !important; color: #fff !important; }
.modal-btn:hover { outline: 2px solid #fff !important; outline-offset: 2px !important; }
.modal-content-dialog.app-dialog-tone-danger { border-color: #ff4a4a !important; }
.modal-content-dialog.app-dialog-tone-danger .modal-title { color: #ff6b6b !important; }
